package com.checkout.payments;

import com.checkout.common.CountryCode;
import com.google.gson.annotations.SerializedName;
import lombok.Data;

import java.util.List;

@Data
public final class PaymentProcessing {

    /**
     * A unique identifier for the authorization submitted to the card scheme during processing.
     * [Optional]
     */
    @SerializedName("retrieval_reference_number")
    private String retrievalReferenceNumber;

    /**
     * A unique identifier for the transaction generated by the acquirer.
     * [Optional]
     */
    @SerializedName("acquirer_transaction_id")
    private String acquirerTransactionId;

    /**
     * The name of the acquirer that processed the payment.
     * [Optional]
     */
    @SerializedName("acquirer_name")
    private String acquirerName;

    /**
     * The two-letter ISO country code of the acquirer country.
     * [Optional]
     */
    @SerializedName("acquirer_country_code")
    private CountryCode acquirerCountryCode;

    /**
     * A code representing the recommended follow-up action for the payment, as provided by Checkout.com.
     * [Optional]
     */
    @SerializedName("recommendation_code")
    private String recommendationCode;

    /**
     * The scheme the transaction was processed with.
     * [Optional]
     */
    private String scheme;

    /**
     * The Merchant Advice Code (MAC) provided by Mastercard with additional transaction information.
     * [Optional]
     */
    @SerializedName("partner_merchant_advice_code")
    private String partnerMerchantAdviceCode;

    /**
     * The original authorization response code sent by the scheme (raw response code).
     * [Optional]
     */
    @SerializedName("partner_response_code")
    private String partnerResponseCode;

    /**
     * Unique order identification of an Afterpay payment.
     * [Optional]
     */
    @SerializedName("partner_order_id")
    private String partnerOrderId;

    /**
     * The partner session identifier associated with the payment.
     * [Optional]
     */
    @SerializedName("partner_session_id")
    private String partnerSessionId;

    /**
     * The client token returned by the partner for client-side initialization.
     * [Optional]
     */
    @SerializedName("partner_client_token")
    private String partnerClientToken;

    /**
     * Unique identification of a payment provided by partner.
     * [Optional]
     */
    @SerializedName("partner_payment_id")
    private String partnerPaymentId;

    /**
     * The type of Primary Account Number (PAN) used: fpan (full card) or dpan (network token).
     * [Optional]
     * Enum: "fpan" "dpan"
     */
    @SerializedName("pan_type_processed")
    private PanProcessedType panTypeProcessed;

    /**
     * A payload used to continue processing for multi-step payment flows.
     * [Optional]
     */
    @SerializedName("continuation_payload")
    private String continuationPayload;

    /**
     * The Payment Unique Number (PUN) assigned to the payment.
     * [Optional]
     */
    private String pun;

    /**
     * The status of the payment as reported by the partner.
     * [Optional]
     */
    @SerializedName("partner_status")
    private String partnerStatus;

    /**
     * Unique transaction identification provided by partner.
     * [Optional]
     */
    @SerializedName("partner_transaction_id")
    private String partnerTransactionId;

    /**
     * Error codes provided by the partner for a failed or declined payment.
     * [Optional]
     */
    @SerializedName("partner_error_codes")
    private List<String> partnerErrorCodes;

    /**
     * Error description provided by the partner.
     * [Optional]
     */
    @SerializedName("partner_error_message")
    private String partnerErrorMessage;

    /**
     * Authorization code provided by the partner.
     * [Optional]
     */
    @SerializedName("partner_authorization_code")
    private String partnerAuthorizationCode;

    /**
     * Authorization response code provided by the partner.
     * [Optional]
     */
    @SerializedName("partner_authorization_response_code")
    private String partnerAuthorizationResponseCode;

    /**
     * Surcharge amount applied to the transaction in minor currency units.
     * [Optional]
     */
    @SerializedName("surcharge_amount")
    private Long surchargeAmount;

    /**
     * Indicates whether a Checkout.com Network Token was available for the payment.
     * [Optional]
     */
    @SerializedName("cko_network_token_available")
    private Boolean ckoNetworkTokenAvailable;

    /**
     * The country where the purchase was made. ISO 3166-1 alpha-2 country code.
     * [Optional]
     * max 2 characters
     */
    @SerializedName("purchase_country")
    private CountryCode purchaseCountry;

    /**
     * The merchant identifier configured with the scheme and used for the payment.
     * [Optional]
     */
    @SerializedName("scheme_merchant_id")
    private String schemeMerchantId;

    /**
     * The foreign retailer amount applied by the merchant, in minor currency units.
     * [Optional]
     */
    @SerializedName("foreign_retailer_amount")
    private Long foreignRetailerAmount;

    /**
     * Indicates whether a network token should be provisioned for the payment.
     * [Optional]
     */
    @SerializedName("provision_network_token")
    private Boolean provisionNetworkToken;

    /**
     * The merchant category code (MCC) associated with the payment.
     * [Optional]
     */
    @SerializedName("merchant_category_code")
    private String merchantCategoryCode;

    /**
     * Indicates whether this is an Account Funding Transaction (AFT).
     * [Optional]
     */
    private Boolean aft;

    /**
     * The Bizum payment identifier returned when processing a Bizum payment.
     * [Optional]
     */
    @SerializedName("bizum_payment_id")
    private String bizumPaymentId;

    /**
     * A reconciliation identifier for the payment.
     * [Optional]
     */
    @SerializedName("reconciliation_id")
    private String reconciliationId;

    /**
     * The aggregator information for this payment.
     * [Optional]
     */
    private Aggregator aggregator;

}
